document.addEventListener("submit",async e=>{if(e.target&&"form-avis-etoiles"===e.target.id){if(e.preventDefault(),!window.AppState.supabase)return;let t=new URLSearchParams(window.location.search).get("prod"),r=e.target.querySelector('button[type="submit"]'),a=e.target.querySelector('input[name="note"]:checked');if(!a)return window.showNotification("⚠️ Veuillez choisir une note !");r.textContent="Envoi...";r.disabled=!0;try{let{error:i}=await window.AppState.supabase.from("commentaires").insert([{produit_id:String(t),nom_client:document.getElementById("avis_nom").value,note:parseInt(a.value),message:document.getElementById("avis_message").value}]);if(i)throw i;e.target.reset();window.showNotification("✅ Merci pour votre avis !");window.chargerAvisProduit(t)}catch(o){window.showNotification("❌ Erreur lors de l'envoi.");console.error(o)}finally{r.textContent="Publier";r.disabled=!1}}});
window.addEventListener("load",()=>{let e=new URLSearchParams(window.location.search).get("prod");e&&setTimeout(()=>window.chargerAvisProduit(e),500)});
if("loading"in HTMLImageElement.prototype){document.querySelectorAll("img[data-src]").forEach(e=>{e.src=e.dataset.src})}else{let t=new IntersectionObserver(e=>{e.forEach(e=>{if(e.isIntersecting){let r=e.target;r.src=r.dataset.src;t.unobserve(r)}})});document.querySelectorAll("img[data-src]").forEach(e=>t.observe(e))}